import { NikElement } from "./nik-element.mjs";
import { html } from "lit";
import { DeferredTask } from "./DeferredTask.mjs";

export class Alert extends NikElement {
  static properties = {
    message: { type: String },
    category: { type: String },
  };

  connectedCallback() {
    super.connectedCallback();

    this.removeSelfTask = new DeferredTask(() => this.removeSelf(), 5000, {
      finalizeBeforeUnload: true,
    });
    this.removeSelfTask.arm();
  }

  removeSelf() {
    this.remove();
  }

  render() {
    return html`<wa-callout variant=${this.category}>
      ${this.message}
      <wa-button
        class="icon-button"
        appearance="plain"
        @click=${this.removeSelf}
        ><wa-icon
          label="Remove"
          name="system/close-large-line"
          library="remix"
        ></wa-icon
      ></wa-button>
    </wa-callout>`;
  }
}

customElements.define("nb-alert", Alert);
